/**
 * Deep Real-World E2E QA — Browser UI Verification v2
 *
 * Reads .qa-context.json (generated by scripts/e2e-qa/run-qa.ts) and
 * verifies every role's UI pages against EXACT values from the API layer.
 *
 * Usage:
 *   npx playwright test e2e/qa-realworld.spec.ts --project=chromium --no-deps
 *
 * Prerequisite: npx tsx scripts/e2e-qa/run-qa.ts (must pass 75/75 first)
 *
 * Design rules:
 *   - Every assertion checks EXACT values (not just "page loads")
 *   - Wallet balances verified to exact ETB amounts
 *   - Fee amounts verified per transaction
 *   - Analytics revenue verified to exact total
 *   - No text.includes("something") unless value is truly dynamic
 */

import { test, expect, Page } from "@playwright/test";
import * as fs from "fs";
import * as path from "path";

// ---------------------------------------------------------------------------
// Context from API suite
// ---------------------------------------------------------------------------
const CONTEXT_PATH = path.join(__dirname, "../scripts/e2e-qa/.qa-context.json");

// Fixed values that never change regardless of trip count
const TRIP1_SHIPPER_FEE = 125.0; // GPS billing: 50km × 2.50/km
const TRIP1_CARRIER_FEE = 125.0;
const TRIP2_SHIPPER_FEE = 1132.5; // Corridor billing: 453km × 2.50/km
const TRIP2_CARRIER_FEE = 1132.5;
const TRIP2_DISTANCE_KM = 453;

interface QAContext {
  superAdminUserId: string;
  adminUserId: string;
  dispatcherUserId: string;
  shipperUserId: string;
  shipperOrgId: string;
  carrierUserId: string;
  carrierOrgId: string;
  truckId: string;
  truckPostingId: string;
  gpsDeviceId: string;
  loadId: string;
  load2Id: string;
  tripId: string;
  trip2Id: string;
  truckRequestId: string;
  addisLocationId: string;
  corridorId: string;
  credentials: Record<string, { email: string; password: string }>;
  shipperFinalBalance: number;
  carrierFinalBalance: number;
  totalPlatformRevenue: number;
  completedTripCount: number;
  shipperTopupAmount: number;
  carrierTopupAmount: number;
  [key: string]: unknown;
}

let ctx: QAContext;

test.beforeAll(() => {
  if (!fs.existsSync(CONTEXT_PATH)) {
    throw new Error(
      `QA context not found at ${CONTEXT_PATH}.\nRun "npx tsx scripts/e2e-qa/run-qa.ts" first (must pass 75/75).`
    );
  }
  ctx = JSON.parse(fs.readFileSync(CONTEXT_PATH, "utf-8"));
});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const ROLE_PORTALS: Record<string, string> = {
  superadmin: "/admin",
  admin: "/admin",
  dispatcher: "/dispatcher",
  shipper: "/shipper",
  carrier: "/carrier",
};

async function uiLogin(page: Page, role: string) {
  const portal = ROLE_PORTALS[role];
  const cred = ctx.credentials[role];
  if (!cred) throw new Error(`No credentials for role "${role}" in QA context`);
  const { email, password } = cred;
  await page.goto(`/login?redirect=${portal}`);
  await page.getByLabel("Email address").fill(email);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: /sign in/i }).click();
  await page.waitForURL((url) => !url.pathname.startsWith("/login"), {
    timeout: 15000,
  });
}

async function goTo(page: Page, url: string) {
  await page.goto(url);
  await page.waitForLoadState("domcontentloaded");
  await page.waitForTimeout(2000);
}

async function pageText(page: Page): Promise<string> {
  return page.innerText("body");
}

async function assertNoErrorPage(page: Page) {
  const text = await pageText(page);
  expect(text).not.toContain("500 Internal Server Error");
  expect(text).not.toContain("Application error");
}

/**
 * Match a formatted number in page text.
 * Handles: "48,742.50", "48742.50", "48,742.5", "ETB 48,742.50", etc.
 * Returns a regex that matches the number with optional thousands separator.
 */
function numPattern(n: number): RegExp {
  const str = n.toFixed(2);
  const [whole, frac] = str.split(".");
  // Build pattern with optional comma thousands separators
  const wholeWithCommas = whole.replace(/\B(?=(\d{3})+(?!\d))/g, ",?");
  // Match with 0-2 decimal places
  if (frac === "00") {
    return new RegExp(`${wholeWithCommas}(\\.00?)?`);
  } else if (frac.endsWith("0")) {
    const short = frac.slice(0, 1);
    return new RegExp(`${wholeWithCommas}\\.${short}0?`);
  } else {
    return new RegExp(`${wholeWithCommas}\\.${frac}`);
  }
}

// ---------------------------------------------------------------------------
// B1 — Super Admin UI
// ---------------------------------------------------------------------------
test.describe.serial("B1 — Super Admin UI", () => {
  let page: Page;

  test.beforeAll(async ({ browser }) => {
    page = await browser.newPage();
    await uiLogin(page, "superadmin");
  });

  test.afterAll(async () => {
    await page.close();
  });

  test("B1.1: Login redirects to /admin", async () => {
    expect(page.url()).toContain("/admin");
  });

  test("B1.2: Users list shows admin Abebe Girma", async () => {
    await goTo(page, "/admin/users");
    await assertNoErrorPage(page);
    await expect(page.getByText("Abebe")).toBeVisible({ timeout: 10000 });
    await expect(page.getByText("Girma")).toBeVisible({ timeout: 5000 });
  });

  test("B1.3: Users list shows all 5 registered users", async () => {
    const text = await pageText(page);
    expect(text).toContain(ctx.credentials.shipper.email);
    expect(text).toContain(ctx.credentials.carrier.email);
  });

  test("B1.4: Audit logs page loads with entries", async () => {
    await goTo(page, "/admin/audit-logs");
    await assertNoErrorPage(page);
    const text = await pageText(page);
    // Audit log should have at least document verification entries
    expect(
      text.includes("VERIFY") ||
        text.includes("verify") ||
        text.includes("Audit") ||
        text.includes("audit")
    ).toBeTruthy();
  });

  test("B1.5: Create Admin form exists (SUPER_ADMIN only)", async () => {
    await goTo(page, "/admin/users/create");
    await assertNoErrorPage(page);
    await expect(
      page.getByLabel("Email").or(page.getByLabel("email"))
    ).toBeVisible({ timeout: 5000 });
  });

  test("B1.6: Corridors page shows Addis-Dire Dawa", async () => {
    await goTo(page, "/admin/corridors");
    await assertNoErrorPage(page);
    const text = await pageText(page);
    expect(text).toContain("Addis Ababa");
    expect(text).toContain("Dire Dawa");
  });
});

