test.describe.serial("B2 — Admin Analytics", () => {
  let page: Page;

  test.beforeAll(async ({ browser }) => {
    page = await browser.newPage();
    await uiLogin(page, "admin");
  });

  test.afterAll(async () => {
    await page.close();
  });

  test("B2.1: Analytics page loads without error", async () => {
    await goTo(page, "/admin/analytics");
    await assertNoErrorPage(page);
  });

  test("B2.2: Platform Revenue shows exact total", async () => {
    // Admin analytics uses formatCurrency with 0 decimals: ETB 2,515
    await expect(
      page.getByText(numPattern(ctx.totalPlatformRevenue)).first()
    ).toBeVisible({ timeout: 10000 });
  });

  test("B2.3: Completed Trips stat card shows 2", async () => {
    // trips.completed.toLocaleString() → "2"
    const text = await pageText(page);
    // Find "Completed Trips" label near a "2" value
    const completedSection = page.locator("text=Completed Trips").locator("..");
    await expect(completedSection).toBeVisible({ timeout: 5000 });
    const sectionText = await completedSection.locator("..").innerText();
    expect(sectionText).toContain(String(ctx.completedTripCount));
  });

  test("B2.4: Load count stat card shows real data", async () => {
    const text = await pageText(page);
    // At least "Loads" or "Total Loads" card with a number > 0
    expect(text).toMatch(/loads?/i);
  });

  test("B2.5: Revenue stat card has currency label", async () => {
    const text = await pageText(page);
    expect(text).toContain("ETB");
  });
});

