// ---------------------------------------------------------------------------
// B7 — Transaction & Fee Detail Verification
// ---------------------------------------------------------------------------
test.describe.serial("B7 — Transaction & Fee Verification", () => {
  test("B7.1: Shipper wallet total spent matches sum of fees", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "shipper");
    await goTo(page, "/shipper/wallet");
    await assertNoErrorPage(page);

    const text = await pageText(page);
    // "Total Spent" or similar label should show sum of both fees
    // 125 + 1132.50 = 1257.50
    expect(text).toMatch(
      numPattern(ctx.shipperTopupAmount - ctx.shipperFinalBalance)
    );
    await page.close();
  });

  test("B7.2: Carrier wallet shows starting balance deposit", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "carrier");
    await goTo(page, "/carrier/wallet");
    await assertNoErrorPage(page);

    const text = await pageText(page);
    // The initial top-up of 30,000 should appear as a DEPOSIT transaction
    expect(text).toMatch(numPattern(ctx.carrierTopupAmount));
    await page.close();
  });

  test("B7.3: Shipper wallet shows starting balance deposit", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "shipper");
    await goTo(page, "/shipper/wallet");
    await assertNoErrorPage(page);

    const text = await pageText(page);
    // The initial top-up of 50,000 should appear as a DEPOSIT transaction
    expect(text).toMatch(numPattern(ctx.shipperTopupAmount));
    await page.close();
  });

  test("B7.4: Admin analytics revenue equals shipper + carrier fees", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "admin");
    await goTo(page, "/admin/analytics");
    await assertNoErrorPage(page);

    // Total platform revenue = 2515 (sum of all shipper + carrier fees)
    await expect(
      page.getByText(numPattern(ctx.totalPlatformRevenue)).first()
    ).toBeVisible({ timeout: 10000 });
    await page.close();
  });

  test("B7.5: Admin loads page shows trip with service fee data", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "admin");
    await goTo(page, "/admin/loads");
    await assertNoErrorPage(page);

    const text = await pageText(page);
    expect(text).toContain("Dire Dawa");
    await page.close();
  });
});

// ---------------------------------------------------------------------------
// B8 — Security Boundaries & Edge Cases
// ---------------------------------------------------------------------------
test.describe.serial("B8 — Security & Edge Cases", () => {
  test("B8.1: Shipper cannot access /carrier/trucks", async ({ browser }) => {
    const page = await browser.newPage();
    await uiLogin(page, "shipper");
    await page.goto("/carrier/trucks");
    await page.waitForLoadState("domcontentloaded");
    await page.waitForTimeout(3000);

    const url = page.url();
    const text = await pageText(page);
    expect(
      url.includes("unauthorized") ||
        url.includes("login") ||
        text.includes("Unauthorized") ||
        text.includes("Access Denied") ||
        text.includes("not authorized")
    ).toBeTruthy();
    await page.close();
  });

  test("B8.2: Carrier cannot access /shipper/loads", async ({ browser }) => {
    const page = await browser.newPage();
    await uiLogin(page, "carrier");
    await page.goto("/shipper/loads");
    await page.waitForLoadState("domcontentloaded");
    await page.waitForTimeout(3000);

    const url = page.url();
    const text = await pageText(page);
    expect(
      url.includes("unauthorized") ||
        url.includes("login") ||
        text.includes("Unauthorized") ||
        text.includes("Access Denied") ||
        text.includes("not authorized")
    ).toBeTruthy();
    await page.close();
  });

  test("B8.3: Dispatcher cannot access /admin/wallets", async ({ browser }) => {
    const page = await browser.newPage();
    await uiLogin(page, "dispatcher");
    await page.goto("/admin/wallets");
    await page.waitForLoadState("domcontentloaded");
    await page.waitForTimeout(3000);

    const url = page.url();
    const text = await pageText(page);
    expect(
      url.includes("unauthorized") ||
        url.includes("login") ||
        text.includes("Unauthorized") ||
        text.includes("Access Denied") ||
        text.includes("not authorized")
    ).toBeTruthy();
    await page.close();
  });

  test("B8.4: Admin (non-super) cannot create admin users", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "admin");
    await goTo(page, "/admin/users/create");
    // Page should either block or show error — not crash
    await assertNoErrorPage(page);
    await page.close();
  });

  test("B8.5: Unauthenticated user redirects to login", async ({ browser }) => {
    const page = await browser.newPage();
    await page.goto("/shipper/wallet");
    await page.waitForLoadState("domcontentloaded");
    await page.waitForTimeout(3000);
    expect(page.url()).toContain("/login");
    await page.close();
  });

  test("B8.6: Shipper documents page shows lock (org approved)", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "shipper");
    await goTo(page, "/shipper/documents");
    await assertNoErrorPage(page);
    const text = await pageText(page).then((t) => t.toLowerCase());
    expect(
      text.includes("locked") ||
        text.includes("approved") ||
        text.includes("verified") ||
        text.includes("cannot upload")
    ).toBeTruthy();
    await page.close();
  });

  test("B8.7: Carrier trip detail page loads for completed trip", async ({
    browser,
  }) => {
    const page = await browser.newPage();
    await uiLogin(page, "carrier");
    await goTo(page, `/carrier/trips/${ctx.tripId}`);
    await assertNoErrorPage(page);
    const text = await pageText(page);
    expect(text).toMatch(/Completed|COMPLETED|Delivered|DELIVERED/);
    await page.close();
  });

  test("B8.8: Admin trip detail shows trip data", async ({ browser }) => {
    const page = await browser.newPage();
    await uiLogin(page, "admin");
    await goTo(page, `/admin/trips/${ctx.tripId}`);
    await assertNoErrorPage(page);
    const text = await pageText(page);
    expect(text).toContain("Dire Dawa");
    await page.close();
  });
});
